import { Vex } from '@vex_dev/sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

export async function validateLegalOutput(aiOutput: string) {
  const result = await vex.check({
    content: aiOutput,
    policy: 'legal-compliance',
    rules: [
      {
        type: 'citation_validation',
        pattern: /([A-Za-z\s]+v\.[\sA-Za-z]+),\s(\d{4})\s([A-Z]+\s\d+)/,
        action: 'block',
        metadata: { db: 'caselaw.access' }
      },
      {
        type: 'privilege_detection',
        keywords: ['confidential', 'attorney-client', 'work product'],
        action: 'quarantine'
      }
    ]
  });
  return result;
}

